import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import "./styles.css"
function Mainweatherpage() {
    let [cityinput, changeinput] = useState("")
    let [fullweatherdata, changefullweather] = useState({})
    let [bool, changebool] = useState(false)
    function function1(e) { 
        changeinput(e.target.value)
    }
    async function apicall() {
        try {
        let weatherdata  = await fetch(`https://api.openweathermap.org/data/2.5/weather?q=${cityinput[0].toUpperCase() + cityinput.slice(1)}&appid=d782528f491fa0b8359a25fc07739daa&units=metric`)
        let updatedweather = await weatherdata.json()
        let alldata = {maindata: updatedweather.main, city: updatedweather.name, weathertype: updatedweather.weather[0]}
        await fetch("http://localhost:5000/weathersession", {
            method: "POST",
            headers: {"Content-Type":"application/json"},
            credentials: "include",
            body: JSON.stringify({citysessionback: alldata})
        })
        let alldataweather =  await fetch("http://localhost:5000/weatherrender", {
            method: "GET",
            credentials: "include"
        })
        let updatedalldata = await alldataweather.json()
        changefullweather(updatedalldata)
        } catch(err) {
            console.log(err)
        }
    }
    return<>
        <div className="weather-app">
  <div className="controls">
    <input
      value={cityinput}
      onChange={(e) => function1(e)}
      type="text"
      placeholder="Enter city (e.g. London)"
    />
    <button onClick={() => apicall()}>Look at the weather</button>
  </div>

  <div className="weather-main">
    <div className="city">
      <p className="label">My location</p>
      <p className="name">{fullweatherdata.city || "—"}</p>
    </div>

    <div className="temp">
      <div className="degrees">{Math.floor(fullweatherdata.maindata.temp) || "—"}°</div>
      <div className="type">{fullweatherdata.weathertype.main || "—"}</div>
    </div>
  </div>

  <div className="stats" role="list" aria-label="Weather details">
    <div className="stat" role="listitem">
      <div className="val">{Math.floor(fullweatherdata.maindata.temp_max) || "—"}°</div>
      <div className="k">High</div>
    </div>
    <div className="stat" role="listitem">
      <div className="val">{Math.floor(fullweatherdata.maindata.temp_min) || "—"}°</div>
      <div className="k">Low</div>
    </div>
    <div className="stat" role="listitem">
      <div className="val">{Math.floor(fullweatherdata.maindata.feels_like) || "—"}°</div>
      <div className="k">Feels like</div>
    </div>
    <div className="stat" role="listitem">
      <div className="val">{fullweatherdata.maindata.humidity ?? "—"}%</div>
      <div className="k">Humidity</div>
    </div>
  </div>

  <div className="weather-footer">
    <span>Data provided by your API</span>
    <span style={{opacity:0.85}}>Updated just now</span>
  </div>
</div>
    </>
}
export default Mainweatherpage
